import json
data = json.loads(input_data)
documentOrGrantReference = ""
legalDescriptor = ""
tenureClass = "Plan"
for p in data['hasPart']:
    if p['type'] == 'crowntenureClass':
      if 'ref' in p:
        tenureClass = p['ref'].split(":")[1].title()
      else:
        tenureClass = "Not Defined"
    elif  p['type'] == 'documentOrGrantReference':
      documentOrGrantReference = "Town Lot"
    elif  p['type'] == 'legalDescriptor':
      legalDescriptor = p['label']
output_data=f"{tenureClass}-{documentOrGrantReference}-{legalDescriptor}"

